@namespace sv_0b3f702b7be44e71bf41cd2796c4aa64.Components.Pages.Board

<div class="kanban-column">
    <div class="column-header">
        <h3>@Title</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>
    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>
    <div class="column-footer">
        <AddTaskForm OnSave="OnAddTask" />
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Title { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }
}

@namespace sv_0b3f702b7be44e71bf41cd2796c4aa64.Components.Pages.Board

<div class="board-stats">
    <div class="stat">
        <span class="stat-label">Total</span>
        <span class="stat-value">@Total</span>
    </div>
    <div class="stat">
        <span class="stat-label">To Do</span>
        <span class="stat-value">@TodoCount</span>
    </div>
    <div class="stat">
        <span class="stat-label">In Progress</span>
        <span class="stat-value">@InProgressCount</span>
    </div>
    <div class="stat">
        <span class="stat-label">Done</span>
        <span class="stat-value">@DoneCount</span>
    </div>
    <div class="stat stat-overdue">
        <span class="stat-label">Overdue</span>
        <span class="stat-value">@OverdueCount</span>
    </div>
</div>

@code {
    [Parameter] public int Total { get; set; }
    [Parameter] public int TodoCount { get; set; }
    [Parameter] public int InProgressCount { get; set; }
    [Parameter] public int DoneCount { get; set; }
    [Parameter] public int OverdueCount { get; set; }
}

@namespace sv_0b3f702b7be44e71bf41cd2796c4aa64.Components.Pages.Board

<div class="task-search">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await SearchTermChanged.InvokeAsync(value);
    }
}

