toolArgs.file_text:
@page "/board"
@namespace sv_0b3f702b7be44e71bf41cd2796c4aa64.Components.Pages.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (isLoading)
{
    <p class="board-loading">Loading tasks…</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Total="allTasks.Count"
                TodoCount="todoBucket.Count"
                InProgressCount="inProgressBucket.Count"
                DoneCount="doneBucket.Count"
                OverdueCount="allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <TaskSearchBar SearchTerm="@searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="kanban-board">
        <KanbanColumn Title="To Do"
                      Tasks="filteredTodo"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveRight="id => MoveTask(id, \"In Progress\")"
                      OnAddTask="args => AddTask(args, \"To Do\")" />

        <KanbanColumn Title="In Progress"
                      Tasks="filteredInProgress"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveLeft="id => MoveTask(id, \"To Do\")"
                      OnMoveRight="id => MoveTask(id, \"Done\")"
                      OnAddTask="args => AddTask(args, \"In Progress\")" />

        <KanbanColumn Title="Done"
                      Tasks="filteredDone"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveLeft="id => MoveTask(id, \"In Progress\")"
                      OnAddTask="args => AddTask(args, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    // Unfiltered buckets (used for stats)
    private List<TaskItem> todoBucket => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressBucket => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneBucket => allTasks.Where(t => t.Status == "Done").ToList();

    // Filtered buckets (used for display)
    private List<TaskItem> filteredTodo => ApplyFilter(todoBucket);
    private List<TaskItem> filteredInProgress => ApplyFilter(inProgressBucket);
    private List<TaskItem> filteredDone => ApplyFilter(doneBucket);

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void OnSearchChanged(string value)
    {
        searchTerm = value;
    }

    private List<TaskItem> ApplyFilter(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
            return tasks;

        return tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            await LoadTasks();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) args, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            if (created.Status != status)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, status);
            }
            await LoadTasks();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to add task: {ex.Message}";
        }
